"use strict";parserFactory.register("lightnovelfr.com",()=>new LightnovelfrParser);class LightnovelfrParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll(".eplister a")].map(this.linkToChapter).reverse()}linkToChapter(e){return{sourceUrl:e.href,title:e.querySelector(".epl-num").textContent+" "+e.querySelector(".epl-title").textContent}}findContent(e){return e.querySelector(".entry-content")||e.querySelector(".postbody")}findChapterTitle(e){let r=e.querySelector(".epheader");if(null!==r){let e=r.querySelector("h1"),t=r.querySelector(".cat-series");return e.textContent+" "+t.textContent}return e.querySelector("h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".sertothumb")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".sersys")]}}